    )
  ORDER BY CASE WHEN (${membershipSql} <> '' AND rm."Membership" = ${membershipSql}) THEN 0 ELSE 1 END, rm.id
  LIMIT 1
), member_rows AS (
  SELECT
    rm.id AS raw_member_id,
    rm."Membership" AS membership,
    rm."Status" AS status,
    rm."Payment" AS payment,
    rm."Share Contact Detail" AS share_contact_detail,
    rm."Venue ID" AS venue_id,
    rm."British Tennis Number" AS british_tennis_number,
    rm."Email address" AS email_address,
    rm."Phone number" AS phone_number,
    rm."Mobile number" AS mobile_number,
    rm."Address 1" AS address_1,
    rm."Address 2" AS address_2,
    rm."Address 3" AS address_3,
    rm."Town" AS town,
    rm."County" AS county,
    rm."Postcode" AS postcode,
    rm."Start Date" AS start_date,
    rm."Date joined venue" AS date_joined_venue,
    rm."Cost" AS cost,
    rm."Paid" AS paid_total,
    rm."Paid Cash" AS paid_cash,
    rm."Paid Credit Card" AS paid_credit_card,
    rm."Paid Direct Debit" AS paid_direct_debit
  FROM public.raw_members rm
  CROSS JOIN base_member bm
  WHERE COALESCE(rm.is_current, true) = true
    AND (
      (bm.venue_id IS NOT NULL AND NULLIF(trim(rm."Venue ID"), '') = bm.venue_id)
      OR (bm.british_tennis_number IS NOT NULL AND NULLIF(trim(COALESCE(rm."British Tennis Number"::text, '')), '') = bm.british_tennis_number)
      OR (
        bm.email_address IS NOT NULL
        AND trim(concat_ws(' ', rm."First name", rm."Last name")) = bm.member_name
        AND public.normalize_match_email(rm."Email address") = public.normalize_match_email(bm.email_address)
