  ORDER BY rm."Membership", rm.id
), contact_rows AS (
  SELECT
    rc.id AS raw_contact_id,
    rc."Venue ID" AS venue_id,
    rc."Share Contact Detail" AS share_contact_detail,
    rc."Email address" AS email_address,
    rc."Phone number" AS phone_number,
    rc."Mobile number" AS mobile_number,
    rc."Address 1" AS address_1,
    rc."Address 2" AS address_2,
    rc."Address 3" AS address_3,
    rc.town,
    rc.county,
    rc.postcode
  FROM public.raw_contacts rc
  CROSS JOIN base_member bm
  WHERE COALESCE(rc.is_current, true) = true
    AND (
      (bm.venue_id IS NOT NULL AND NULLIF(trim(rc."Venue ID"), '') = bm.venue_id)
      OR (
        bm.email_address IS NOT NULL
        AND trim(concat_ws(' ', rc."First name", rc."Last name")) = bm.member_name
        AND public.normalize_match_email(rc."Email address") = public.normalize_match_email(bm.email_address)
      )
      OR (
        bm.venue_id IS NULL AND bm.email_address IS NULL
        AND trim(concat_ws(' ', rc."First name", rc."Last name")) = bm.member_name
      )
    )
  ORDER BY rc.id
), best_contact AS (
  SELECT to_jsonb(bc) AS best_contact
  FROM base_member bm
  LEFT JOIN LATERAL public.resolve_best_contact_row(
    bm.member_name,
    bm.email_address,
    NULLIF(regexp_replace(bm.member_name, '^\\S+\\s*', ''), ''),
    EXISTS (SELECT 1 FROM member_rows WHERE membership ILIKE '%Family%')
  ) bc ON TRUE
), signup_rows AS (
  SELECT
    ms.id,
    ms.signup_date,
    ms.product,
    ms.email_address,
    ms.method,
    ms.source,
    ms.batch_id
  FROM public.member_signups ms
  CROSS JOIN base_member bm
  WHERE trim(COALESCE(ms.member, '')) = bm.member_name
    AND EXISTS (SELECT 1 FROM member_rows mr WHERE mr.membership = ms.product)
    AND (
      (bm.email_address IS NOT NULL AND public.normalize_match_email(ms.email_address) = public.normalize_match_email(bm.email_address))
      OR (
        bm.email_address IS NULL
        AND 1 = (
          SELECT count(*)
          FROM public.raw_members rm2
          WHERE COALESCE(rm2.is_current, true) = true
            AND trim(concat_ws(' ', rm2."First name", rm2."Last name")) = bm.member_name
            AND rm2."Membership" = ms.product
        )
      )
    )
  ORDER BY ms.signup_date DESC NULLS LAST, ms.id DESC
), template_defaults AS (
  SELECT
    MAX(CASE WHEN key = 'gmail_test_email_template_key' THEN value END) AS default_email_template_key,
    MAX(CASE WHEN key = 'email_delivery_mode' THEN value END) AS default_delivery_mode
  FROM public.global_settings
  WHERE key IN ('gmail_test_email_template_key', 'email_delivery_mode')
), email_templates AS (
  SELECT json_agg(
    json_build_object(
      'template_key', et.template_key,
      'template_name', COALESCE(NULLIF(et.template_name, ''), et.template_key),
      'template_type', et.template_type
    )
    ORDER BY COALESCE(NULLIF(et.template_name, ''), et.template_key)
  ) AS email_templates
  FROM public.email_templates et
  WHERE et.is_active = true
    AND et.template_type = 0
)
SELECT
  COALESCE((SELECT member_name FROM base_member), ${memberSql})::text AS member,
  (SELECT raw_member_id FROM base_member) AS raw_member_id,
  COALESCE((SELECT json_agg(to_jsonb(mr)) FROM member_rows mr), '[]'::json) AS member_rows,
  COALESCE((SELECT json_agg(to_jsonb(cr)) FROM contact_rows cr), '[]'::json) AS contact_rows,
  COALESCE((SELECT json_agg(to_jsonb(sr)) FROM signup_rows sr), '[]'::json) AS signup_rows,
  COALESCE((SELECT best_contact FROM best_contact), '{}'::jsonb) AS best_contact,
  COALESCE((SELECT email_templates FROM email_templates), '[]'::json) AS email_templates,
  COALESCE((SELECT default_email_template_key FROM template_defaults), '') AS default_email_template_key,
  COALESCE((SELECT default_delivery_mode FROM template_defaults), 'test') AS default_delivery_mode;
`;
